            referenced.update(plural_names)

        # the fallback block is mandatory
        if not parser.stream.current.test("name:fallback"):
            parser.fail(
                "expected 'fallback' block in conditional translation",
                parser.stream.current.lineno,
            )
        next(parser.stream)
        parser.stream.expect("block_end")
        fallback_names, fallback = self._parse_block(parser, False, in_fallback=True)
        referenced.update(fallback_names)
        # leave the trailing block_end for the surrounding subparse to consume
        next(parser.stream)

