                    trans_node,
                    nodes.Dict(
                        [
                            nodes.Pair(nodes.Const(key), value)
                            for key, value in variables.items()
                        ]
                    ),
                )

        # the fallback content is never translated, but still needs the
        # same variable substitution and autoescape handling as old style
        # gettext output.
        fallback_node: nodes.Expr = nodes.MarkSafeIfAutoescape(nodes.Const(fallback))
